import{_ as i,Q as r,S as s,W as e,a4 as t,a2 as n,a5 as o,E as l}from"./framework-291a1352.js";const d={},h=o(`<h1 id="contributing-guidelines" tabindex="-1"><a class="header-anchor" href="#contributing-guidelines" aria-hidden="true">#</a> Contributing Guidelines</h1><h2 id="code-of-conduct" tabindex="-1"><a class="header-anchor" href="#code-of-conduct" aria-hidden="true">#</a> Code of Conduct</h2><p>This is probably way overkill, but this is by far my most active project in terms of contributions, and somewhere along the way I was convinced that it was a good idea to have this in place sooner rather than later:</p><p>I want to provide a safe, healthy environment for all contributors/participants regardless of gender, sexual orientation, disability, race, religion, etc. As such, I don&#39;t tolerate harassment of participants in any form. In particular this applies to my issues tracker, but also to any other means of communication associated with this project that might come up. Anyone who violates these basic rules may be sanctioned/banned/have-their-comments-deleted/etc by my discretion.</p><p>Glad we cleared that up.</p><h2 id="branching" tabindex="-1"><a class="header-anchor" href="#branching" aria-hidden="true">#</a> Branching</h2><p>Before working on your fix/feature/whatever, you should create a new branch to work on. Do something like:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>$ <span class="token function">git</span> checkout <span class="token parameter variable">-b</span> <span class="token string">&#39;my-sweet-new-pull-request&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="please-please-please-start-with-a-test" tabindex="-1"><a class="header-anchor" href="#please-please-please-start-with-a-test" aria-hidden="true">#</a> Please Please Please Start With A Test</h2><p>ecstatic has some pretty gnarly branching/logic underneath. Tests are extremely important because they (a) prove that your feature/fix works, and (b) avoid regressions in the future. Even if your patch is problematic enough to not be merged, a test will still be very helpful for confirming any future fix.</p><p>I won&#39;t reject your patch outright if it&#39;s missing new tests, but it sure helps!</p><h2 id="code-style" tabindex="-1"><a class="header-anchor" href="#code-style" aria-hidden="true">#</a> Code Style</h2><p>Ecstatic lints using a number of modifications on top of airbnb. If you think &quot;airbnb except it doesn&#39;t need to be transpiled for targeted platforms&quot; you&#39;re pretty close.</p><p>Linting is executed as part of pretest. Your code should pass linting before being merged.</p><h2 id="a-few-other-minor-guidelines" tabindex="-1"><a class="header-anchor" href="#a-few-other-minor-guidelines" aria-hidden="true">#</a> A Few Other Minor Guidelines</h2>`,15),c=e("li",null,"Keep your pull requests on-topic. A pull request purporting to tackle A shouldn't also have commits changing B and C. Feel free to make separate pull requests. For instance: A pull request should generally only update dependencies when doing so is required to add the feature or fix the bug. This feature can, of course, consist of updating dependencies.",-1),u=e("li",null,"I prefer maintaining the changelog and package.json version myself. This is because I try to make a single commit for a tagged release contain all changelog additions and the version bump, and this breaks down when there are interstitial commits making updates to either.",-1),p={href:"https://david-dm.org/jfhbrook/node-ecstatic",target:"_blank",rel:"noopener noreferrer"},f=e("img",{src:"https://david-dm.org/jfhbrook/node-ecstatic.svg",alt:"dependencies status",loading:"lazy"},null,-1),m={href:"http://CONTRIBUTORS.md",target:"_blank",rel:"noopener noreferrer"},g=o('<h2 id="pull-request" tabindex="-1"><a class="header-anchor" href="#pull-request" aria-hidden="true">#</a> Pull Request</h2><p>Make a pull request against master with your new branch. Explain briefly what the patch does to the code, along with any concerns.</p><p>(If you don&#39;t have a description, it&#39;s hard for me to put the changes in context. That makes it more difficult for me to merge!)</p><h2 id="keep-it-moving" tabindex="-1"><a class="header-anchor" href="#keep-it-moving" aria-hidden="true">#</a> Keep It Moving</h2><p>I don&#39;t always notice new PRs, and sometimes I will forget to follow up on them. If this happens to you, you can bump the PR thread or find me on IRC or twitter.</p><h2 id="last-rule" tabindex="-1"><a class="header-anchor" href="#last-rule" aria-hidden="true">#</a> LAST RULE</h2><p>HAVE FUN :v :v</p>',7);function b(y,w){const a=l("ExternalLinkIcon");return r(),s("div",null,[h,e("ol",null,[c,u,e("li",null,[t("In case you were wondering about dependencies, you may find this helpful: "),e("a",p,[f,n(a)])]),e("li",null,[t("Please add yourself to "),e("a",m,[t("CONTRIBUTORS.md"),n(a)]),t(" if you haven't done so! Fill in as much as makes you comfortable.")])]),g])}const k=i(d,[["render",b],["__file","CONTRIBUTING.html.vue"]]);export{k as default};
